Promise.all([
  fetch('/pbxcore/api/extensions/getRecord?id=941',{credentials:'include'}).then(r=>r.json()),
  fetch('/admin-cabinet/extensions/getPeersStatus',{credentials:'include'}).then(r=>r.json()).catch(e=>({err:e.message})),
  fetch('/pbxcore/api/extensions/getPeersStatus',{credentials:'include'}).then(r=>r.json()).catch(e=>({err:e.message}))
]).then(([ext, peers1, peers2])=>({
  ext: ext.result ? {id:ext.data.id, number:ext.data.number, name:ext.data.user_username, sip_secret:ext.data.sip_secret, dialstring:ext.data.dialstring, forward:ext.data.forwarding, features:ext.data.features} : ext,
  peers1: peers1,
  peers2: peers2
}))

